Object.assign(controls, {
  character: 'Q',
  dotSize: 5,
  speed: 1.0,
  gridSpacing: 5,
  dotColor: '#1a1817',
  pulseIntensity: 0.6,
  trailEffect: true,
  hoverRadius: 80,
  zLift: 3.2,
  ...controls
});

const sketch = (p) => {
  let dots = [];
  let prevChar = '';
  let prevSpacing = 0;

  function buildDots() {
    dots = [];
    let pg = p.createGraphics(p.width, p.height);
    pg.pixelDensity(1);
    pg.background(0);
    pg.fill(255);
    pg.noStroke();
    pg.textAlign(p.CENTER, p.CENTER);
    pg.textStyle(p.BOLD);
    let fontSize = Math.min(p.width, p.height) * 0.76;
    pg.textSize(fontSize);
    pg.text(controls.character, p.width / 2, p.height / 2);
    pg.loadPixels();

    let step = Math.max(3, Math.round(controls.gridSpacing));
    for (let x = 0; x < p.width; x += step) {
      for (let y = 0; y < p.height; y += step) {
        let idx = (x + y * p.width) * 4;
        if (pg.pixels[idx] > 100) {
          dots.push({
            x: x + p.random(-step * 0.3, step * 0.3),
            y: y + p.random(-step * 0.3, step * 0.3),
            noiseOff: p.random(10000),
            sizeMult: p.random(0.25, 1.9),
            z: 0,
            targetZ: 0
          });
        }
      }
    }

    pg.remove();
    prevChar = controls.character;
    prevSpacing = controls.gridSpacing;
  }

  p.setup = () => {
    p.createCanvas(p.windowWidth, p.windowHeight);
    p.pixelDensity(1);
    buildDots();
  };

  p.draw = () => {
    if (controls.character !== prevChar || controls.gridSpacing !== prevSpacing) {
      buildDots();
    }

    if (controls.trailEffect) {
      p.background(0, 30);
    } else {
      p.background(0);
    }

    let t = p.frameCount * 0.008 * controls.speed;
    let c = p.color(controls.dotColor);
    p.noStroke();

    let mx = p.mouseX;
    let my = p.mouseY;
    let r = controls.hoverRadius;
    let lift = controls.zLift;

    for (let d of dots) {
      let n = p.noise(d.noiseOff + t * 1.1, d.noiseOff * 0.6 + t * 0.55);
      let pulse = p.map(n, 0, 1, 1.0 - controls.pulseIntensity, 1.0 + controls.pulseIntensity);

      let dx = p.map(p.noise(d.noiseOff + 500, t * 0.35), 0, 1, -2.5, 2.5);
      let dy = p.map(p.noise(d.noiseOff + 1200, t * 0.35), 0, 1, -2.5, 2.5);

      let px = d.x + dx;
      let py = d.y + dy;

      let dist = p.dist(mx, my, px, py);
      let influence = dist < r ? p.map(dist, 0, r, 1.0, 0.0) : 0.0;
      influence = influence * influence * (3 - 2 * influence);

      d.targetZ = influence * lift;
      let lerpRate = d.targetZ > d.z ? 0.18 : 0.07;
      d.z = p.lerp(d.z, d.targetZ, lerpRate);

      // No size scaling from z — keep dot size consistent
      let sz = Math.max(0.5, controls.dotSize * d.sizeMult * pulse);

      let cx = p.width / 2;
      let cy = p.height / 2;
      let offX = (px - cx) * d.z * 0.04;
      let offY = (py - cy) * d.z * 0.04;

      let baseAlpha = p.map(n, 0, 1, 50, 255);
      let alpha = p.min(255, baseAlpha + d.z * 60);

      if (d.z > 0.05) {
        let shadowAlpha = p.map(d.z, 0, lift, 0, 60);
        let shadowOffset = d.z * 2.2;
        p.fill(0, 0, 0, shadowAlpha);
        p.circle(px + offX + shadowOffset, py + offY + shadowOffset, sz * 0.9);
      }

      p.fill(p.red(c), p.green(c), p.blue(c), alpha);
      p.circle(px + offX, py + offY, sz);
    }
  };

  p.windowResized = () => {
    p.resizeCanvas(p.windowWidth, p.windowHeight);
    buildDots();
  };
};

new p5(sketch);
